mapper.insert:
merge into sys_notice_read a using (
select #{noticeId} as notice_id, #{userId} as user_id from dual
) b on (a.notice_id = b.notice_id AND a.user_id = b.user_id) when not matched then insert (read_id, notice_id, user_id, read_time) values (seq_sys_notice_read.nextval, b.notice_id, b.user_id, sysdate)
